  grid-template-columns: 1fr;
  gap: var(--space-lg);
  padding-top: var(--space-lg);
  padding-bottom: var(--space-xl);
}

.main {
  background: white;
  border-radius: var(--radius-md);
  padding: var(--space-lg);
  box-shadow: var(--shadow-sm);
  border: 1px solid var(--color-border);
}

.sidebar {
  background: white;
  border-radius: var(--radius-md);
  padding: var(--space-md);
  box-shadow: var(--shadow-sm);
  border: 1px solid var(--color-border);
}

/* Footer */
.footer {
  margin-top: var(--space-lg);
  padding: var(--space-md) 0;
  color: var(--color-muted);
  font-size: 0.9rem;
  text-align: center;
}

/* Cards */
.card {
  background: white;
  border-radius: var(--radius-md);
  padding: var(--space-md);
  box-shadow: var(--shadow-sm);
  border: 1px solid var(--color-border);
}

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  padding: 0.5rem 0.9rem;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  font-weight: 600;
  color: #fff;
  background: var(--color-primary);
  box-shadow: var(--shadow-sm);
  transition: transform 120ms ease, box-shadow 120ms ease, background-color 120ms ease;
  text-decoration: none;
}

.btn:hover {
  transform: translateY(-1px);
  background: var(--color-primary-600);
}

.btn:active {
  transform: translateY(0);
}

.btn.secondary {
  background: linear-gradient(90deg, #eef2ff, #f8f9ff);
  color: var(--color-text);
  box-shadow: none;
  border: 1px solid var(--color-border);
}

/* Form elements */
input[type="text"],
input[type="email"],
textarea,
select {
  width: 100%;
  padding: 0.6rem 0.75rem;
  border-radius: var(--radius-sm);
  border: 1px solid var(--color-border);
  background: white;
  color: var(--color-text);
  font-size: 0.95rem;
  outline: none;
}

input:focus,
textarea:focus,
select:focus {
  box-shadow: 0 0 0 4px rgba(11,103,255,0.08);
  border-color: var(--color-primary);
}

/* Utility text */
.text-muted { color: var(--color-muted); font-size: 0.9rem; }
.lead { font-size: 1.125rem; color: rgba(15,23,42,0.9); }

/* Responsive behavior */
@media (min-width: 768px) {
  .layout {
    grid-template-columns: 2fr 1fr;
    align-items: start;
  }

  .nav a {
    font-size: 1rem;
  }
}

/* Accessibility & reduced motion */
:focus {
  outline: 3px solid rgba(11,103,255,0.14);
  outline-offset: 2px;
}

@media (prefers-reduced-motion: reduce) {
  * { transition: none !important; animation: none !important; scroll-behavior: auto !important; }
}

/* Small helpers */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
  white-space: nowrap;
  border: 0;
}

/* Lists */
.menu {
  list-style: none;
  padding: 0;
  margin: 0;
}

.menu li + li {
  margin-top: var(--space-xs);
}

/* Table basics */
.table {
  width: 100%;
  border-collapse: collapse;
  background: white;
  border-radius: var(--radius-sm);
  overflow: hidden;
}

.table th,
.table td {
  padding: 0.6rem 0.75rem;
  text-align: left;
  border-bottom: 1px solid var(--color-border);
}

/* Alerts */
.alert {
  padding: var(--space-sm);
  border-radius: var(--radius-sm);
  border: 1px solid rgba(0,0,0,0.04);
  background: linear-gradient(180deg, rgba(255,255,255,0.6), rgba(255,255,255,0.4));
  color: var(--color-text);
}

/* Small responsive tweaks */
@media (min-width: 1024px) {
  .container { max-width: 1280px; }
}

